import pytest

def test_create_employee_unauthenticated_returns_401(unauthenticated_session):
    payload = {
        "first_name": "Eve",
        "last_name": "Hacker",
        "email": "eve.hacker.test@example.com",
        "department": "Security",
        "start_date": "2024-06-01"
    }
    resp = unauthenticated_session.post("/employees", json=payload)
    assert resp.status_code == 401, (
        f"Expected 401 for unauthenticated request, got {resp.status_code}"
    )

import pytest

def test_create_employee_forbidden_role_returns_403(viewer_session):
    payload = {
        "first_name": "Carol",
        "last_name": "Viewer",
        "email": "carol.viewer.test@example.com",
        "department": "Finance",
        "start_date": "2024-07-01"
    }
    resp = viewer_session.post("/employees", json=payload)
    assert resp.status_code == 403, (
        f"Expected 403 for viewer role, got {resp.status_code}"
    )
